import * as React from "react"
import { Link as GatsbyLink } from "gatsby"
import { Container } from "./ui"
import PoemNavDropdown from "./poem-nav-dropdown"

interface NavItem {
  label: string
  path: string
}

const navItems: NavItem[] = [
  { label: "Home", path: "/" },
  { label: "Biography", path: "/biography" },
  { label: "Published Work", path: "/published-work" },
  { label: "Poems", path: "/poems" },
  { label: "E-books", path: "/e-books" },
]

interface MainNavProps {
  showPoemDropdown?: boolean
}

export default function MainNav({ showPoemDropdown }: MainNavProps) {
  const [isOpen, setIsOpen] = React.useState(false)

  return (
    <nav className="mainNav">
      <Container>
        {/* Desktop nav — hidden below 992px via SCSS */}
        <ul className="mainNavDesktop">
          {navItems.map((item) => (
            <li key={item.path}>
              <GatsbyLink to={item.path} className="mainNavLink">
                {item.label}
              </GatsbyLink>
            </li>
          ))}
        </ul>

        {/* Mobile bar: hamburger left, poems dropdown right — hidden above 992px */}
        <div className="mainNavMobileBar">
          <button
            className="mainNavHamburger"
            onClick={() => setIsOpen((prev) => !prev)}
            aria-label={isOpen ? "Close menu" : "Open menu"}
            aria-expanded={isOpen}
          >
            {isOpen ? (
              <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
                <line x1="18" y1="6" x2="6" y2="18" />
                <line x1="6" y1="6" x2="18" y2="18" />
              </svg>
            ) : (
              <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
                <line x1="3" y1="6" x2="21" y2="6" />
                <line x1="3" y1="12" x2="21" y2="12" />
                <line x1="3" y1="18" x2="21" y2="18" />
              </svg>
            )}
          </button>

          {showPoemDropdown && <PoemNavDropdown />}
        </div>
      </Container>

      {/* Mobile main nav dropdown */}
      {isOpen && (
        <ul className="mainNavMobile">
          {navItems.map((item) => (
            <li key={item.path}>
              <GatsbyLink
                to={item.path}
                className="mainNavMobileLink"
                onClick={() => setIsOpen(false)}
              >
                {item.label}
              </GatsbyLink>
            </li>
          ))}
        </ul>
      )}
    </nav>
  )
}
